parameters.jsCode:
return [{
  json: {
    shipmentId: 'SH-2026-001',
    route: {
      origin: 'Los Angeles, CA',
      destination: 'Chicago, IL',
      distance: 2015
    },
    cargo: {
      type: 'Electronics',
      weight: 15000,
      value: 250000
    },
    requirements: {
      deliveryDate: '2026-03-01',
      equipment: 'Dry Van',
      insurance: true
    }
  }
}];

const shipment = $input.first().json;

// Calculate market rate
const baseRate = shipment.route.distance * 2.50; // $2.50/mile
const weightFactor = shipment.cargo.weight > 10000 ? 1.2 : 1.0;
const equipmentFactor = shipment.requirements.equipment === 'Reefer' ? 1.3 : 1.0;

const carriers = [
  { name: 'Swift Transport', rating: 4.8, baseRate: baseRate * 0.95 },
  { name: 'J.B. Hunt', rating: 4.9, baseRate: baseRate * 1.05 },
  { name: 'Schneider', rating: 4.7, baseRate: baseRate * 0.98 }
];

// Get quotes
const quotes = carriers.map(c => ({
  carrier: c.name,
  rating: c.rating,
  quote: Math.round(c.baseRate * weightFactor * equipmentFactor),
  transitTime: '2-3 days'
})).sort((a, b) => a.quote - b.quote);

return [{
  json: {
    ...shipment,
    marketRate: Math.round(baseRate),
    quotes,
    recommended: quotes[0],
    savingsVsMarket: Math.round(baseRate - quotes[0].quote)
  }
}];

// Automated negotiation logic
const data = $input.first().json;
const bestQuote = data.quotes[0];

// Try to negotiate 5% lower
const negotiatedRate = Math.round(bestQuote.quote * 0.95);

return [{
  json: {
    ...data,
    negotiation: {
      attempted: true,
      originalQuote: bestQuote.quote,
      negotiatedRate: negotiatedRate,
      savings: bestQuote.quote - negotiatedRate,
      carrier: bestQuote.carrier,
      message: `We've negotiated a special rate of $${negotiatedRate} with ${bestQuote.carrier} based on our volume commitment.`
    }
  }
}];

